            AppRoutes = """["/sales-orders"]""",
            Tags = """["sales-orders","sales","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"so1","text":"A customer calls to confirm their quote and place an order. What is the correct first step?","options":[{"id":"a","text":"Create a new job on the kanban board for the customer's parts"},{"id":"b","text":"Convert the accepted quote to a sales order, which carries over the quote link and line items","isCorrect":true},{"id":"c","text":"Create an invoice directly from the quote"},{"id":"d","text":"Go to Shipments and create a shipment for the quoted parts"}],"explanation":"When a quote is accepted, you convert it to a sales order. This creates the order with the quote's line items and keeps a link back to the quote. From the order, you then drive production, shipping, and invoicing."},{"id":"so2","text":"You're creating a new sales order. Which of the following is NOT required to save the order?","options":[{"id":"a","text":"Selecting a customer"},{"id":"b","text":"Adding at least one line item"},{"id":"c","text":"Setting the tax rate"},{"id":"d","text":"Entering the customer's PO number","isCorrect":true}],"explanation":"Customer PO is optional — not all customers send purchase orders. However, a customer selection, at least one line item, and a tax rate (which defaults to 0) are all required to save."},{"id":"so3","text":"A sales order is in Confirmed status. The customer wants to cancel. What can you do?","options":[{"id":"a","text":"Delete the order permanently from the system"},{"id":"b","text":"Cancel the order — cancellation is allowed from Draft or Confirmed status","isCorrect":true},{"id":"c","text":"Nothing — confirmed orders cannot be cancelled or modified"},{"id":"d","text":"Change the status back to Draft first, then cancel"}],"explanation":"Orders can be cancelled from either Draft or Confirmed status. Once an order moves to In Production or beyond, cancellation is no longer available. Note that Delete is only available for Draft orders."},{"id":"so4","text":"You've shipped 50 out of 100 units on a sales order line. What status does the order show?","options":[{"id":"a","text":"Shipped — any shipment changes the status"},{"id":"b","text":"In Production — the order stays in production until all units ship"},{"id":"c","text":"Partially Shipped — some lines have shipped quantities but not all are fully fulfilled","isCorrect":true},{"id":"d","text":"Draft — partial shipments don't affect status"}],"explanation":"When some but not all line items are fully shipped, the order shows Partially Shipped with a yellow label. Each line tracks its own shipped-versus-ordered count. The order moves to Shipped only when every line is fully fulfilled."},{"id":"so5","text":"On a sales order, you notice a line item's shipped quantity is shown in green. What does this mean?","options":[{"id":"a","text":"The line item is on backorder"},{"id":"b","text":"The line item is fully shipped — everything the customer ordered has gone out","isCorrect":true},{"id":"c","text":"The line item's shipment is in transit"},{"id":"d","text":"The line item has been invoiced"}],"explanation":"Green on the shipped count means the line is fully shipped — nothing left to send. Yellow means partially shipped: some has gone out, but not all. The colors give you a quick read on where each line stands."},{"id":"so6","text":"When adding a line item to a new sales order, where do parts come from?","options":[{"id":"a","text":"You type in a free-text part description — no part catalog lookup"},{"id":"b","text":"You search the parts catalog as you type — only Active parts show, by part number and description","isCorrect":true},{"id":"c","text":"You select from a list of all parts regardless of status"},{"id":"d","text":"Parts are automatically pulled from the linked quote"}],"explanation":"The line's part field searches the parts catalog as you type, showing only Active parts (so you can't accidentally sell an obsolete one). Results read as 'Part # — Description', and you pick one from the list."},{"id":"so7","text":"Where can you see how a sales order connects to its source quote?","options":[{"id":"a","text":"In the Sales Orders list — there's a Quote column showing the link"},{"id":"b","text":"On the order's Overview — the Quote field shows the quote number, and you click it to open the quote","isCorrect":true},{"id":"c","text":"Quotes and sales orders are not linked"},{"id":"d","text":"Only in the Reports module under Order Traceability"}],"explanation":"The order's Overview shows the linked quote number. Click it to open that quote, giving you full traceability from quote to order — handy when a customer questions what was agreed."},{"id":"so8","text":"You want to find all orders for a specific customer that haven't shipped yet. How do you filter the list?","options":[{"id":"a","text":"Use the Search field to type the customer name and manually scan for non-shipped statuses"},{"id":"b","text":"Set the Customer filter to the specific customer, then set the Status filter to Draft, Confirmed, or In Production"},{"id":"c","text":"Go to the customer's detail page and check their Orders tab"},{"id":"d","text":"Both B and C would work","isCorrect":true}],"explanation":"The sales orders list page has both Customer and Status filters. Select the customer from the dropdown and then filter by status. You could also navigate to the customer's detail page and check their Orders tab for a customer-centric view."},{"id":"so9","text":"What happens to the financial summary when you change the tax rate on a sales order?","options":[{"id":"a","text":"Nothing changes until you save"},{"id":"b","text":"The Tax amount and Total update right away as you type the new rate","isCorrect":true},{"id":"c","text":"You must click a Recalculate button to update the totals"},{"id":"d","text":"Tax is calculated per line item, not for the whole order"}],"explanation":"The summary works out subtotal, tax (subtotal times the rate), and grand total as you go. Change the tax rate or a line item and the totals update right away."},{"id":"so10","text":"A Draft sales order can be deleted, but a Confirmed order cannot. Why?","options":[{"id":"a","text":"Confirmed orders have been communicated to the customer — deletion would break the audit trail. Cancellation preserves the record.","isCorrect":true},{"id":"b","text":"There is no difference — both can be deleted"},{"id":"c","text":"Confirmed orders are locked by the accounting system"},{"id":"d","text":"It's a bug — confirmed orders should also be deletable"}],"explanation":"Draft orders haven't been committed, so deletion is safe. Confirmed orders represent a business commitment — deleting them would break the audit trail. Instead, you cancel a confirmed order, which preserves the record with a Cancelled status for history and traceability."},{"id":"so11","text":"How is the new-order window for a sales order laid out differently from a simple form?","options":[{"id":"a","text":"It uses a single-column form like most other forms"},{"id":"b","text":"It uses two sides — line items on the left, order details and summary on the right","isCorrect":true},{"id":"c","text":"It opens as a full-page view instead of a window"},{"id":"d","text":"It's a step-by-step wizard with separate pages for details and lines"}],"explanation":"The new-order window has two sides. The left holds the line items and the row for adding another (part, quantity, unit price). The right holds order details (customer, PO, credit terms, delivery date, tax rate), notes, and a live summary of subtotal, tax, and total."},{"id":"so12","text":"You've opened a sales order and want to send a coworker straight to it. What's the easiest way?","options":[{"id":"a","text":"You can't — orders can only be found by searching the list"},{"id":"b","text":"Copy the link while the order is open and share it — it opens the same order for them","isCorrect":true},{"id":"c","text":"Screenshot the order and email the picture"},{"id":"d","text":"Read them the order number over the phone so they can search for it"}],"explanation":"When an order is open you can bookmark it or copy its link and share it. A coworker who opens that link lands on the same order — a quick way to hand off a specific order without making them search for it."}]}"""
